## Implementation Plan: Booking Popup Optimization

---

### FILE 1: `src/components/booking-modal.tsx`

**CHANGE:** Fix 5 bugs + add 3 UX improvements:
1. Body scroll lock when modal opens (missing — background scrolls under modal)
2. Escape key handler (missing — standard modal UX)
3. `handleClose` doesn't reset `formData` (user re-opens modal and sees stale data)
4. Hidden `required` input for time is ignored by browsers (constraint validation skips hidden inputs — time can be empty on submit)
5. `today` is recomputed on every render — move to `useMemo`
6. Add Vietnamese phone format validation (10 digits starting with 0)
7. Disable time slots that have already passed when today is selected
8. Add "Bất kỳ thợ" (any barber) option so barber field is not a hard blocker

**CODE:**

```tsx
"use client";

import { useState, useEffect, useMemo } from "react";
import { X, Calendar, Clock, User, Phone, Scissors, Send } from "lucide-react";
import { SERVICES, BARBERS, TIME_SLOTS } from "@/data/site-data";

const GOOGLE_SCRIPT_URL = ""; // TODO: Paste Google Apps Script URL here

interface BookingModalProps {
  isOpen: boolean;
  onClose: () => void;
}

type FormStatus = "idle" | "submitting" | "success" | "error";

const EMPTY_FORM = {
  name: "",
  phone: "",
  service: "",
  barber: "",
  date: "",
  time: "",
};

// Vietnamese phone: 10 digits, starts with 0
const PHONE_RE = /^0\d{9}$/;

export default function BookingModal({ isOpen, onClose }: BookingModalProps) {
  const [formData, setFormData] = useState(EMPTY_FORM);
  const [status, setStatus] = useState<FormStatus>("idle");
  const [phoneError, setPhoneError] = useState("");

  // FIX 1: Body scroll lock
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }
    return () => {
      document.body.style.overflow = "";
    };
  }, [isOpen]);

  // FIX 2: Escape key handler
  useEffect(() => {
    if (!isOpen) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") handleClose();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [isOpen, status]); // eslint-disable-line react-hooks/exhaustive-deps

  // FIX 5: Stable today value
  const today = useMemo(() => new Date().toISOString().split("T")[0], []);

  // FIX 7: Disable past time slots when today is selected
  const now = new Date();
  const availableSlots = useMemo(() => {
    if (formData.date !== today) return TIME_SLOTS;
    const currentMinutes = now.getHours() * 60 + now.getMinutes();
    return TIME_SLOTS.filter((slot) => {
      const [h, m] = slot.split(":").map(Number);
      return h * 60 + m > currentMinutes;
    });
  }, [formData.date, today]); // eslint-disable-line react-hooks/exhaustive-deps

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // FIX 6: Vietnamese phone validation
    if (!PHONE_RE.test(formData.phone)) {
      setPhoneError("Số điện thoại phải gồm 10 chữ số, bắt đầu bằng 0");
      return;
    }

    // FIX 4: Explicit time guard (hidden required doesn't work in browsers)
    if (!formData.time) {
      return;
    }

    setStatus("submitting");
    try {
      if (GOOGLE_SCRIPT_URL) {
        await fetch(GOOGLE_SCRIPT_URL, {
          method: "POST",
          mode: "no-cors",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(formData),
        });
      }
      setStatus("success");
      setTimeout(() => {
        setStatus("idle");
        setFormData(EMPTY_FORM);
        onClose();
      }, 2500);
    } catch {
      setStatus("error");
      setTimeout(() => setStatus("idle"), 3000);
    }
  };

  // FIX 3: handleClose also resets formData
  const handleClose = () => {
    if (status === "submitting") return;
    setStatus("idle");
    setFormData(EMPTY_FORM);
    setPhoneError("");
    onClose();
  };

  return (
    <div
      className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4"
      onClick={handleClose}
    >
      <div
        className="bg-dark-light rounded-2xl max-w-lg w-full max-h-[90vh] overflow-y-auto border border-white/10"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-white/10">
          <div>
            <h2
              className="text-xl font-bold text-white uppercase tracking-wider"
              style={{ fontFamily: "Darker Grotesque, sans-serif" }}
            >
              Đặt Lịch <span className="text-gold">Cắt Tóc</span>
            </h2>
            <p className="text-white/50 text-sm mt-1">Chọn dịch vụ và thời gian phù hợp</p>
          </div>
          <button
            onClick={handleClose}
            className="text-white/50 hover:text-white p-1 transition-colors"
            aria-label="Đóng"
          >
            <X size={22} />
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="p-5 space-y-4">
          {/* Name */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <User size={14} /> Họ và tên
            </label>
            <input
              type="text"
              required
              value={formData.name}
              onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              placeholder="Nhập họ tên"
              className="w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white placeholder-white/30 focus:border-gold focus:outline-none transition-colors"
            />
          </div>

          {/* Phone — FIX 6: with validation error */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <Phone size={14} /> Số điện thoại
            </label>
            <input
              type="tel"
              required
              value={formData.phone}
              onChange={(e) => {
                setFormData({ ...formData, phone: e.target.value });
                setPhoneError("");
              }}
              placeholder="Nhập số điện thoại (VD: 0901234567)"
              className={`w-full bg-dark-lighter border rounded-lg px-4 py-2.5 text-white placeholder-white/30 focus:outline-none transition-colors ${
                phoneError ? "border-red-500 focus:border-red-500" : "border-white/10 focus:border-gold"
              }`}
            />
            {phoneError && <p className="text-red-400 text-xs mt-1">{phoneError}</p>}
          </div>

          {/* Service */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <Scissors size={14} /> Dịch vụ
            </label>
            <select
              required
              value={formData.service}
              onChange={(e) => setFormData({ ...formData, service: e.target.value })}
              className="w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white focus:border-gold focus:outline-none transition-colors appearance-none cursor-pointer"
            >
              <option value="" className="bg-dark-lighter">Chọn dịch vụ</option>
              {SERVICES.map((s) => (
                <option key={s.name} value={s.name} className="bg-dark-lighter">
                  {s.name} - {s.price}
                </option>
              ))}
            </select>
          </div>

          {/* Barber — FIX 8: "Bất kỳ thợ" option */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <User size={14} /> Thợ cắt tóc
            </label>
            <select
              required
              value={formData.barber}
              onChange={(e) => setFormData({ ...formData, barber: e.target.value })}
              className="w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white focus:border-gold focus:outline-none transition-colors appearance-none cursor-pointer"
            >
              <option value="" className="bg-dark-lighter">Chọn thợ cắt tóc</option>
              <option value="Bất kỳ" className="bg-dark-lighter">Bất kỳ thợ nào</option>
              {BARBERS.map((b) => (
                <option key={b.id} value={b.name} className="bg-dark-lighter">
                  {b.name}
                </option>
              ))}
            </select>
          </div>

          {/* Date */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <Calendar size={14} /> Ngày
            </label>
            <input
              type="date"
              required
              min={today}
              value={formData.date}
              onChange={(e) => setFormData({ ...formData, date: e.target.value, time: "" })}
              className="w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white focus:border-gold focus:outline-none transition-colors cursor-pointer"
            />
          </div>

          {/* Time Slots — FIX 4 + FIX 7 */}
          <div>
            <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
              <Clock size={14} /> Giờ
              {formData.date === today && (
                <span className="text-white/30 text-xs">(Các giờ đã qua bị ẩn)</span>
              )}
            </label>
            {availableSlots.length === 0 ? (
              <p className="text-white/40 text-sm py-3 text-center">
                Hôm nay không còn khung giờ trống. Vui lòng chọn ngày khác.
              </p>
            ) : (
              <div className="grid grid-cols-4 gap-2">
                {availableSlots.map((slot) => (
                  <button
                    key={slot}
                    type="button"
                    onClick={() => setFormData({ ...formData, time: slot })}
                    className={`py-2 rounded-lg text-sm font-bold transition-colors cursor-pointer ${
                      formData.time === slot
                        ? "bg-gold text-black"
                        : "bg-dark-lighter border border-white/10 text-white/70 hover:border-gold/30 hover:text-white"
                    }`}
                  >
                    {slot}
                  </button>
                ))}
              </div>
            )}
            {/* FIX 4: Remove useless hidden required — validate in handleSubmit instead */}
          </div>

          {/* Submit */}
          <button
            type="submit"
            disabled={status === "submitting" || !formData.time}
            className="w-full bg-gold hover:bg-gold-dark disabled:opacity-50 disabled:cursor-not-allowed text-black font-bold py-3 rounded-lg transition-colors flex items-center justify-center gap-2 mt-2 cursor-pointer"
          >
            {status === "submitting" ? (
              <>
                <div className="w-5 h-5 border-2 border-black/30 border-t-black rounded-full animate-spin" />
                Đang gửi...
              </>
            ) : status === "success" ? (
              "Đặt lịch thành công! ✓"
            ) : status === "error" ? (
              "Có lỗi xảy ra, thử lại"
            ) : (
              <>
                <Send size={18} />
                Xác Nhận Đặt Lịch
              </>
            )}
          </button>
        </form>
      </div>
    </div>
  );
}
```

